{
  "name": "Orbit - Brand Strategy OS",
  "description": "An infinite spatial canvas for brand teams to plan, strategize, and manage campaigns. Features smart cards, AI-powered brainstorming, and visual asset management."
}

export enum CardType {
  POST = 'POST',
  STRATEGY_AI = 'STRATEGY_AI',
  ANALYTICS = 'ANALYTICS',
  PERSONA = 'PERSONA'
}

export interface Position {
  x: number;
  y: number;
}

export interface CardData {
  id: string;
  type: CardType;
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex: number;
  // Generic data bucket for different card needs
  content: any;
}

export interface Workspace {
  id: string;
  name: string;
  cards: CardData[];
}

export interface AppState {
  workspaces: Workspace[];
  activeWorkspaceId: string;
  scale: number;
  pan: Position;
}

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateMarketingStrategy = async (
  topic: string, 
  audience: string, 
  tone: string
): Promise<string> => {
  if (!apiKey) {
    return "Error: No API Key configured. Please set the API_KEY environment variable.";
  }

  try {
    const prompt = `
      Act as a world-class creative director. 
      I need 5 distinct marketing hooks/angles for the following context:
      Topic/Product: ${topic}
      Target Audience: ${audience}
      Tone: ${tone}

      Format the output as a clean HTML list (<ul><li>...</li></ul>) without markdown backticks. 
      Keep each hook punchy and under 20 words.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "No response generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Failed to generate strategy. Please try again.";
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'icon';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-lg transition-colors focus:outline-none focus:ring-2 focus:ring-offset-1 disabled:opacity-50 disabled:cursor-not-allowed font-medium";

  const variants = {
    primary: "bg-blue-600 text-white hover:bg-blue-700 shadow-sm focus:ring-blue-500",
    secondary: "bg-white text-gray-700 border border-gray-200 hover:bg-gray-50 shadow-sm focus:ring-gray-200",
    ghost: "text-gray-600 hover:bg-gray-100 hover:text-gray-900",
    icon: "text-gray-500 hover:bg-gray-100 p-2 rounded-full"
  };

  const sizes = {
    sm: "px-3 py-1.5 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base"
  };

  const finalClass = `${baseStyles} ${variants[variant]} ${variant === 'icon' ? '' : sizes[size]} ${className}`;

  return (
    <button className={finalClass} {...props}>
      {children}
    </button>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CardData, CardType } from '../../types';
import { GripHorizontal, X, maximize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title: string;
  accentColor?: string;
  icon?: React.ReactNode;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete,
  zoomScale,
  children,
  title,
  accentColor = "border-gray-200",
  icon
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });

  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent canvas panning
    onSelect(card.id);
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX, y: e.clientY };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale]);

  return (
    <div
      className={`absolute flex flex-col bg-white rounded-2xl shadow-xl transition-shadow duration-200 ${
        isSelected ? 'ring-2 ring-blue-500 shadow-2xl z-50' : 'hover:shadow-2xl z-10'
      }`}
      style={{
        left: card.x,
        top: card.y,
        width: card.width,
        minHeight: card.height,
        // Using transform for scale is tricky with absolute positioning, handling scaling in parent wrapper usually better
        // but for now relying on canvas scale.
      }}
      onClick={(e) => {
        e.stopPropagation();
        onSelect(card.id);
      }}
    >
      {/* Header / Drag Handle */}
      <div 
        className={`flex items-center justify-between px-4 py-3 border-b ${accentColor} cursor-grab active:cursor-grabbing rounded-t-2xl bg-gray-50/50 backdrop-blur-sm`}
        onMouseDown={handleMouseDown}
      >
        <div className="flex items-center gap-2 text-gray-700 font-semibold select-none">
          {icon}
          <span className="text-sm uppercase tracking-wide opacity-80">{title}</span>
        </div>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
           <button onClick={() => onDelete(card.id)} className="p-1 hover:bg-red-50 hover:text-red-500 rounded text-gray-400">
             <X size={16} />
           </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 p-4 overflow-visible">
        {children}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BaseCard } from './BaseCard';
import { CardData } from '../../types';
import { FileImage, Paperclip, MessageSquare, CheckSquare, Plus, Trash2 } from 'lucide-react';
import { Button } from '../ui/Button';

interface PostCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
}

export const PostCard: React.FC<PostCardProps> = (props) => {
  const [title, setTitle] = useState(props.card.content?.title || "New Campaign Post");
  const [date, setDate] = useState(props.card.content?.date || "");
  const [caption, setCaption] = useState(props.card.content?.caption || "");
  const [tasks, setTasks] = useState<{id: number, text: string, done: boolean}[]>(props.card.content?.tasks || [
    { id: 1, text: "Draft Copy", done: false },
    { id: 2, text: "Approve Assets", done: false }
  ]);
  const [assetCount, setAssetCount] = useState(props.card.content?.assetCount || 1);

  const toggleTask = (id: number) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, done: !t.done } : t));
  };

  const addTask = () => {
    setTasks([...tasks, { id: Date.now(), text: "New Task", done: false }]);
  };

  return (
    <BaseCard {...props} title={`POST #${props.card.id.split('-')[1] || '001'}`} icon={<FileImage size={18} className="text-purple-600"/>} accentColor="border-purple-100">
      <div className="space-y-4">
        {/* Meta Section */}
        <div className="flex gap-2">
          <input 
            className="flex-1 font-bold text-gray-800 text-lg bg-transparent border-none focus:ring-0 p-0 placeholder-gray-300" 
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Post Title..."
          />
          <input 
            type="date" 
            className="text-xs text-gray-500 bg-gray-50 border rounded px-2 py-1"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </div>

        {/* References Grid */}
        <div>
          <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2 block">References</label>
          <div className="grid grid-cols-4 gap-2">
             {[...Array(assetCount)].map((_, i) => (
               <div key={i} className="aspect-square bg-gray-100 rounded-lg border border-dashed border-gray-300 flex items-center justify-center hover:bg-gray-50 cursor-pointer group relative overflow-hidden">
                 {i === 0 ? (
                    <img src="https://picsum.photos/100/100" alt="Ref" className="w-full h-full object-cover opacity-80" />
                 ) : (
                    <Paperclip size={16} className="text-gray-400" />
                 )}
               </div>
             ))}
             <button onClick={() => setAssetCount(c => c+1)} className="aspect-square flex items-center justify-center border border-dashed border-blue-200 bg-blue-50/50 rounded-lg text-blue-400 hover:bg-blue-50">
               <Plus size={16} />
             </button>
          </div>
        </div>

        {/* Caption */}
        <textarea 
          className="w-full text-sm text-gray-600 bg-gray-50 border-0 rounded-lg p-3 resize-none focus:ring-1 focus:ring-purple-200"
          rows={3}
          placeholder="Write your caption here..."
          value={caption}
          onChange={(e) => setCaption(e.target.value)}
        />

        {/* Todo List */}
        <div className="bg-yellow-50/50 p-3 rounded-lg border border-yellow-100">
           <div className="flex items-center justify-between mb-2">
              <label className="text-xs font-semibold text-yellow-600 uppercase">To-Do</label>
              <button onClick={addTask}><Plus size={14} className="text-yellow-600"/></button>
           </div>
           <div className="space-y-1">
             {tasks.map(task => (
               <div key={task.id} className="flex items-center gap-2 group">
                 <button onClick={() => toggleTask(task.id)} className={`w-4 h-4 rounded border flex items-center justify-center ${task.done ? 'bg-yellow-400 border-yellow-400' : 'bg-white border-gray-300'}`}>
                   {task.done && <CheckSquare size={10} className="text-white" />}
                 </button>
                 <input 
                    value={task.text} 
                    onChange={(e) => setTasks(tasks.map(t => t.id === task.id ? {...t, text: e.target.value} : t))}
                    className={`bg-transparent text-sm w-full border-none focus:ring-0 p-0 ${task.done ? 'line-through text-gray-400' : 'text-gray-700'}`}
                 />
                 <button onClick={() => setTasks(tasks.filter(t => t.id !== task.id))} className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-red-400">
                    <Trash2 size={12} />
                 </button>
               </div>
             ))}
           </div>
        </div>

        {/* Footer Actions */}
        <div className="flex items-center justify-between pt-2 border-t border-gray-100">
          <div className="flex -space-x-2">
            <div className="w-6 h-6 rounded-full bg-blue-500 border-2 border-white flex items-center justify-center text-[10px] text-white font-bold">JD</div>
            <div className="w-6 h-6 rounded-full bg-gray-200 border-2 border-white flex items-center justify-center text-[10px] text-gray-500 font-bold">+</div>
          </div>
          <div className="flex gap-2">
             <Button variant="ghost" size="sm" className="text-gray-400 hover:text-blue-500">
               <MessageSquare size={16} />
             </Button>
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

import React, { useState } from 'react';
import { BaseCard } from './BaseCard';
import { CardData } from '../../types';
import { Sparkles, Bot, Loader2, ArrowRight } from 'lucide-react';
import { Button } from '../ui/Button';
import { generateMarketingStrategy } from '../../services/geminiService';

interface AiStrategyCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
}

export const AiStrategyCard: React.FC<AiStrategyCardProps> = (props) => {
  const [topic, setTopic] = useState("");
  const [audience, setAudience] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!topic) return;
    setLoading(true);
    const strategy = await generateMarketingStrategy(topic, audience, "Professional yet punchy");
    setResult(strategy);
    setLoading(false);
  };

  return (
    <BaseCard {...props} title="The Oracle (AI)" icon={<Sparkles size={18} className="text-indigo-500"/>} accentColor="border-indigo-100">
      <div className="space-y-4">
        <div className="bg-indigo-50/50 p-3 rounded-lg border border-indigo-100/50">
          <p className="text-xs text-indigo-800 mb-2 font-medium">Strategize with Gemini</p>
          <div className="space-y-2">
            <input 
              className="w-full text-sm px-3 py-2 rounded border border-indigo-200 bg-white focus:ring-2 focus:ring-indigo-300 outline-none" 
              placeholder="What are we promoting?"
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
            />
            <input 
              className="w-full text-sm px-3 py-2 rounded border border-indigo-200 bg-white focus:ring-2 focus:ring-indigo-300 outline-none" 
              placeholder="Target Audience?"
              value={audience}
              onChange={(e) => setAudience(e.target.value)}
            />
            <Button 
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white flex items-center justify-center gap-2"
              onClick={handleGenerate}
              disabled={loading || !topic}
            >
              {loading ? <Loader2 className="animate-spin" size={16} /> : <Bot size={16} />}
              Generate Hooks
            </Button>
          </div>
        </div>

        {result && (
          <div className="animate-in fade-in duration-500">
             <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">Generated Angles</div>
             <div 
               className="text-sm text-gray-700 space-y-2 prose prose-sm prose-ul:list-disc prose-ul:pl-4"
               dangerouslySetInnerHTML={{ __html: result }}
             />
             <Button variant="secondary" size="sm" className="w-full mt-3 text-xs" onClick={() => setResult(null)}>
               Clear & Restart
             </Button>
          </div>
        )}
      </div>
    </BaseCard>
  );
};

