import React, { useRef, useState, useEffect } from 'react';
import { CardData, CardType, Position } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
}

export const Canvas: React.FC<CanvasProps> = ({ cards, onCardsChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);

  // Background pattern calculations
  const patternSize = 40 * scale;
  const dotSize = 2 * scale;

  const handleWheel = (e: WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const s = Math.exp(-e.deltaY * 0.01);
      setScale(prev => Math.min(Math.max(0.1, prev * s), 4));
    } else {
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    // Middle click or Space+Click (simulated here just by clicking background) starts pan
    if (e.button === 0 || e.button === 1) {
      setIsPanning(true);
      setLastMousePos({ x: e.clientX, y: e.clientY });
      setSelectedCardId(null); // Deselect cards
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
    }
  };

  const handleMouseUp = () => {
    setIsPanning(false);
  };

  const updateCardPosition = (id: string, x: number, y: number) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
  };

  const handleDeleteCard = (id: string) => {
    onCardsChange(cards.filter(c => c.id !== id));
  };

  const bringToFront = (id: string) => {
    setSelectedCardId(id);
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardId === card.id,
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      default:
        return <PostCard {...commonProps} />;
    }
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#f3f4f6] relative overflow-hidden cursor-grab active:cursor-grabbing"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* Dot Grid Background */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-20"
        style={{
          backgroundImage: `radial-gradient(#9ca3af ${dotSize}px, transparent 0)`,
          backgroundSize: `${patternSize}px ${patternSize}px`,
          backgroundPosition: `${pan.x}px ${pan.y}px`,
        }}
      />

      {/* World Transform Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
        }}
      >
        {cards.map(renderCard)}
      </div>

      {/* Scale Indicator */}
      <div className="absolute bottom-6 right-6 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-mono border border-gray-200 shadow-sm pointer-events-none">
        {Math.round(scale * 100)}%
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { 
  Layout, 
  Plus, 
  Layers, 
  Settings, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users, 
  Menu 
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'Summer Campaign',
    cards: [
      { id: 'card-post-1', type: CardType.POST, x: 400, y: 150, width: 340, height: 400, zIndex: 1, content: { title: 'Launch Teaser', date: '2024-06-01' } },
      { id: 'card-ai-1', type: CardType.STRATEGY_AI, x: 800, y: 150, width: 320, height: 300, zIndex: 2, content: {} }
    ]
  },
  {
    id: 'ws-2',
    name: 'Evergreen Content',
    cards: []
  }
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 160 - (Math.random() * 50),
      y: window.innerHeight / 2 - 200 - (Math.random() * 50),
      width: type === CardType.ANALYTICS ? 380 : 340,
      height: 200, // Grows automatically
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: 'New Strategy',
      cards: []
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  return (
    <div className="w-full h-screen flex overflow-hidden text-gray-800">

      {/* Left Sidebar (Workspaces) */}
      <div className="w-64 bg-white border-r border-gray-200 flex flex-col z-20 shadow-[4px_0_24px_rgba(0,0,0,0.02)]">
        <div className="h-16 flex items-center px-6 border-b border-gray-100">
          <div className="w-8 h-8 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-lg flex items-center justify-center text-white mr-3 shadow-lg shadow-blue-200">
            <Layout size={18} />
          </div>
          <span className="font-bold text-lg tracking-tight">Orbit</span>
        </div>

        <div className="flex-1 overflow-y-auto py-4">
          <div className="px-4 mb-2 text-xs font-semibold text-gray-400 uppercase tracking-wider">Workspaces</div>
          <div className="space-y-1 px-2">
            {workspaces.map(ws => (
              <button
                key={ws.id}
                onClick={() => setActiveWorkspaceId(ws.id)}
                className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors ${
                  activeWorkspaceId === ws.id 
                    ? 'bg-blue-50 text-blue-700 font-medium' 
                    : 'text-gray-600 hover:bg-gray-50'
                }`}
              >
                {ws.name}
              </button>
            ))}
          </div>
          <button 
            onClick={addWorkspace}
            className="mx-5 mt-4 text-xs flex items-center gap-1 text-gray-400 hover:text-blue-600 transition-colors"
          >
            <Plus size={12} /> New Workspace
          </button>
        </div>

        <div className="p-4 border-t border-gray-100">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 rounded-full bg-gray-100 border border-gray-200 flex items-center justify-center text-gray-500 font-semibold text-xs">JD</div>
             <div className="flex-1">
               <div className="text-xs font-medium text-gray-900">John Doe</div>
               <div className="text-[10px] text-gray-500">Pro Plan</div>
             </div>
             <Settings size={16} className="text-gray-400 cursor-pointer hover:text-gray-600"/>
          </div>
        </div>
      </div>

      {/* Main Canvas Area */}
      <div className="flex-1 relative">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />

        {/* Floating Toolbar */}
        <div className="absolute top-6 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-xl border border-white/50 shadow-2xl shadow-gray-200/50 rounded-2xl px-2 py-2 flex items-center gap-1 z-30">
          <ToolbarButton 
            icon={<FileImage size={20} />} 
            label="Post" 
            onClick={() => addCard(CardType.POST)}
            color="hover:bg-purple-50 hover:text-purple-600"
          />
          <div className="w-px h-6 bg-gray-200 mx-1"></div>
          <ToolbarButton 
            icon={<Sparkles size={20} />} 
            label="AI Strategy" 
            onClick={() => addCard(CardType.STRATEGY_AI)} 
            color="hover:bg-indigo-50 hover:text-indigo-600"
          />
          <ToolbarButton 
            icon={<BarChart2 size={20} />} 
            label="Analytics" 
            onClick={() => addCard(CardType.ANALYTICS)}
            color="hover:bg-emerald-50 hover:text-emerald-600"
          />
          <ToolbarButton 
             icon={<Users size={20} />} 
             label="Persona" 
             onClick={() => {}} // Placeholder logic for now
             color="hover:bg-orange-50 hover:text-orange-600"
          />
        </div>
      </div>
    </div>
  );
}

const ToolbarButton = ({ icon, label, onClick, color }: { icon: React.ReactNode, label: string, onClick: () => void, color: string }) => (
  <button 
    onClick={onClick}
    className={`group relative p-3 rounded-xl text-gray-500 transition-all duration-200 ${color}`}
  >
    {icon}
    <span className="absolute -bottom-8 left-1/2 -translate-x-1/2 bg-gray-900 text-white text-[10px] py-1 px-2 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
      {label}
    </span>
  </button>
);

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CardType {
  POST = 'POST',
  STRATEGY_AI = 'STRATEGY_AI',
  ANALYTICS = 'ANALYTICS',
  PERSONA = 'PERSONA'
}

export interface Position {
  x: number;
  y: number;
}

export interface TaskItem {
  id: string;
  text: string;
  done: boolean;
}

export interface TaskList {
  id: string;
  title: string;
  color: 'yellow' | 'blue' | 'red' | 'green' | 'gray';
  items: TaskItem[];
}

export interface MediaItem {
  id: string;
  type: 'image' | 'link' | 'video' | 'empty';
  url?: string;
  thumbnail?: string;
}

export interface Comment {
  id: string;
  user: string;
  avatar: string; // Initials
  text: string;
  timestamp: string;
}

export interface PostCardContent {
  sku?: string;
  title?: string;
  date?: string;
  caption?: string;
  references?: MediaItem[];
  finalAssets?: MediaItem[];
  taskLists?: TaskList[];
  comments?: Comment[];
  assignees?: string[];
}

export interface CardData {
  id: string;
  type: CardType;
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex: number;
  // Generic data bucket, type-casted in components based on CardType
  content: PostCardContent | any;
}

export interface Workspace {
  id: string;
  name: string;
  cards: CardData[];
}

export interface AppState {
  workspaces: Workspace[];
  activeWorkspaceId: string;
  scale: number;
  pan: Position;
}

import React, { useState, useEffect } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, TaskList, TaskItem, MediaItem, Comment } from '../../types';
import { 
  FileImage, Paperclip, MessageSquare, CheckSquare, Plus, Trash2, 
  MoreHorizontal, Link as LinkIcon, Image as ImageIcon, X, Send, UserPlus
} from 'lucide-react';
import { Button } from '../ui/Button';

interface PostCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
}

// --- Helper Components ---

const MediaCube = ({ item, index, onRemove, onUpdate }: { item: MediaItem, index: number, onRemove: () => void, onUpdate: (i: MediaItem) => void }) => {
  const [isHovered, setIsHovered] = useState(false);

  // Simulation of upload/link actions
  const handleUpload = () => {
    onUpdate({ ...item, type: 'image', url: `https://picsum.photos/200/200?random=${Math.random()}` });
  };

  const handleLink = () => {
    onUpdate({ ...item, type: 'link', url: 'https://example.com' });
  };

  return (
    <div 
      className="aspect-square relative group rounded-md border border-gray-200 bg-gray-50 overflow-hidden transition-all hover:border-blue-300 hover:shadow-sm"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {item.type === 'empty' ? (
        <div className="w-full h-full flex flex-col items-center justify-center gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
           <div className="flex gap-1">
             <button onClick={(e) => { e.stopPropagation(); handleUpload(); }} className="p-1 hover:bg-gray-200 rounded text-gray-600"><ImageIcon size={14}/></button>
             <button onClick={(e) => { e.stopPropagation(); handleLink(); }} className="p-1 hover:bg-gray-200 rounded text-gray-600"><LinkIcon size={14}/></button>
           </div>
           <span className="text-[9px] font-medium uppercase text-gray-400">Add</span>
        </div>
      ) : (
        <>
          {item.type === 'image' && <img src={item.url} alt="asset" className="w-full h-full object-cover" />}
          {item.type === 'link' && <div className="w-full h-full flex items-center justify-center bg-blue-50 text-blue-500"><LinkIcon size={20}/></div>}

          {/* Action Overlay */}
          {isHovered && (
            <button 
              onClick={(e) => { e.stopPropagation(); onRemove(); }}
              className="absolute top-1 right-1 bg-white/90 p-1 rounded-sm text-red-500 hover:bg-red-50 shadow-sm"
            >
              <X size={10} />
            </button>
          )}
        </>
      )}
    </div>
  );
};

const TaskListBlock = ({ list, onUpdate, onDelete }: { list: TaskList, onUpdate: (l: TaskList) => void, onDelete: () => void }) => {
  const [newItemText, setNewItemText] = useState("");

  const colorStyles = {
    yellow: "bg-yellow-50/50 border-yellow-100 text-yellow-800",
    blue: "bg-blue-50/50 border-blue-100 text-blue-800",
    red: "bg-red-50/50 border-red-100 text-red-800",
    green: "bg-emerald-50/50 border-emerald-100 text-emerald-800",
    gray: "bg-gray-50/50 border-gray-200 text-gray-800"
  };

  const addItem = () => {
    if (!newItemText.trim()) return;
    const newItem: TaskItem = { id: Date.now().toString(), text: newItemText, done: false };
    onUpdate({ ...list, items: [...list.items, newItem] });
    setNewItemText("");
  };

  const toggleItem = (itemId: string) => {
    const updatedItems = list.items.map(i => i.id === itemId ? { ...i, done: !i.done } : i);
    onUpdate({ ...list, items: updatedItems });
  };

  const deleteItem = (itemId: string) => {
    onUpdate({ ...list, items: list.items.filter(i => i.id !== itemId) });
  };

  return (
    <div className={`p-3 rounded-lg border ${colorStyles[list.color]} mb-2 transition-all`}>
      <div className="flex items-center justify-between mb-2">
        <input 
          value={list.title}
          onChange={(e) => onUpdate({ ...list, title: e.target.value })}
          className="bg-transparent text-xs font-bold uppercase tracking-wide border-none focus:ring-0 p-0 w-full"
          placeholder="LIST NAME"
        />
        <div className="flex items-center gap-1">
          <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className="text-gray-400 hover:text-red-500 opacity-50 hover:opacity-100">
            <Trash2 size={12}/>
          </button>
        </div>
      </div>

      <div className="space-y-1">
        {list.items.map(item => (
          <div key={item.id} className="flex items-center gap-2 group min-h-[24px]">
            <button 
              onClick={(e) => { e.stopPropagation(); toggleItem(item.id); }}
              className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${item.done ? 'bg-current border-transparent opacity-50' : 'bg-white border-black/10'}`}
            >
              {item.done && <CheckSquare size={10} className="text-white" />}
            </button>
            <input 
              value={item.text}
              onChange={(e) => {
                const updated = list.items.map(i => i.id === item.id ? { ...i, text: e.target.value } : i);
                onUpdate({ ...list, items: updated });
              }}
              className={`bg-transparent text-sm w-full border-none focus:ring-0 p-0 ${item.done ? 'line-through opacity-50' : ''}`}
            />
            <button onClick={(e) => { e.stopPropagation(); deleteItem(item.id); }} className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-red-500">
               <X size={12} />
            </button>
          </div>
        ))}
        <div className="flex items-center gap-2 mt-2 opacity-60 hover:opacity-100">
           <Plus size={14} className="text-current"/>
           <input 
             value={newItemText}
             onChange={(e) => setNewItemText(e.target.value)}
             onKeyDown={(e) => { if(e.key === 'Enter') addItem(); }}
             placeholder="Add item..."
             className="bg-transparent text-sm border-none focus:ring-0 p-0 placeholder-current"
           />
        </div>
      </div>
    </div>
  );
};

// --- Main Component ---

export const PostCard: React.FC<PostCardProps> = (props) => {
  const { card } = props;

  // -- State Initialization --
  // SKU Generation: Guaranteed unique-ish short code
  const [sku] = useState(card.content?.sku || `P-${Math.random().toString(36).substr(2, 4).toUpperCase()}`);

  const [viewMode, setViewMode] = useState<'edit' | 'comments'>('edit');
  const [title, setTitle] = useState(card.content?.title || "Untitled Post");
  const [date, setDate] = useState(card.content?.date || "");
  const [caption, setCaption] = useState(card.content?.caption || "");

  const [references, setReferences] = useState<MediaItem[]>(card.content?.references || [{ id: '1', type: 'empty' }, { id: '2', type: 'empty' }]);
  const [finalAssets, setFinalAssets] = useState<MediaItem[]>(card.content?.finalAssets || [{ id: '1', type: 'empty' }]);

  const [taskLists, setTaskLists] = useState<TaskList[]>(card.content?.taskLists || [
    { id: 'l1', title: 'Production', color: 'yellow', items: [{ id: 't1', text: 'Briefing', done: true }, { id: 't2', text: 'Copywriting', done: false }] }
  ]);

  const [comments, setComments] = useState<Comment[]>(card.content?.comments || []);
  const [newComment, setNewComment] = useState("");

  // -- Handlers --

  const addTaskList = () => {
    const colors: TaskList['color'][] = ['blue', 'green', 'red', 'yellow', 'gray'];
    const randomColor = colors[Math.floor(Math.random() * colors.length)];
    const newList: TaskList = {
      id: Date.now().toString(),
      title: 'New List',
      color: randomColor,
      items: []
    };
    setTaskLists([...taskLists, newList]);
  };

  const handlePostComment = () => {
    if (!newComment.trim()) return;
    const c: Comment = {
      id: Date.now().toString(),
      user: 'You',
      avatar: 'ME',
      text: newComment,
      timestamp: 'Just now'
    };
    setComments([...comments, c]);
    setNewComment("");
  };

  // Header Title with SKU
  const headerTitle = (
    <div className="flex items-baseline gap-2">
      <span className="font-mono text-xs text-purple-600 bg-purple-50 px-1.5 py-0.5 rounded border border-purple-100">{sku}</span>
      <span className="text-sm font-semibold text-gray-600 uppercase tracking-wide">Post</span>
    </div>
  );

  return (
    <BaseCard 
      {...props} 
      title="" // We override header manually via children if needed, but BaseCard expects string. We use the prop for simple title usually.
      // But BaseCard implementation renders title prop. Let's rely on BaseCard's header rendering but customize content below it.
      // Actually, to get the SKU in the header properly based on the provided BaseCard code, we might want to modify BaseCard or just accept standard header.
      // For now, we will let BaseCard render "POST #{ID}" (from existing usage) or we pass the SKU as the title.
      // Better: Let's pass the SKU as the title to BaseCard.
      title={`POST ${sku}`}
      icon={<FileImage size={18} className="text-purple-600"/>} 
      accentColor="border-purple-100"
    >
      <div className="flex flex-col h-full">

        {/* VIEW MODE: EDIT */}
        {viewMode === 'edit' && (
          <div className="space-y-5 animate-in fade-in duration-300">

            {/* 1. Meta Data */}
            <div className="flex gap-3 items-start">
              <textarea 
                className="flex-1 font-bold text-gray-800 text-xl bg-transparent border-none focus:ring-0 p-0 placeholder-gray-300 resize-none leading-tight" 
                rows={2}
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="Campaign Post Title..."
                onClick={(e) => e.stopPropagation()} // Allow text selection without drag
              />
              <input 
                type="date" 
                className="text-[10px] font-medium text-gray-500 bg-gray-50 border border-gray-200 rounded px-2 py-1 h-fit"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                onClick={(e) => e.stopPropagation()}
              />
            </div>

            {/* 2. References (Grid) */}
            <div>
              <div className="flex items-center justify-between mb-2">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">References</label>
                <button onClick={(e) => { e.stopPropagation(); setReferences([...references, { id: Date.now().toString(), type: 'empty' }]); }} className="text-gray-400 hover:text-blue-500"><Plus size={14}/></button>
              </div>
              <div className="grid grid-cols-4 gap-2">
                {references.map((item, i) => (
                  <MediaCube 
                    key={item.id} 
                    item={item} 
                    index={i} 
                    onRemove={() => setReferences(references.filter(r => r.id !== item.id))}
                    onUpdate={(updated) => setReferences(references.map(r => r.id === item.id ? updated : r))}
                  />
                ))}
              </div>
            </div>

            {/* 3. Caption */}
            <div className="relative group">
               <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-1 block">Caption</label>
               <textarea 
                className="w-full text-sm text-gray-700 bg-gray-50/50 border border-gray-100 rounded-lg p-3 resize-none focus:ring-1 focus:ring-purple-200 focus:bg-white transition-all"
                rows={3}
                placeholder="Write your post caption..."
                value={caption}
                onChange={(e) => setCaption(e.target.value)}
                onClick={(e) => e.stopPropagation()}
              />
            </div>

            {/* 4. Production Lists */}
            <div>
              <div className="flex items-center justify-between mb-2">
                 <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Production</label>
                 <button 
                  onClick={(e) => { e.stopPropagation(); addTaskList(); }} 
                  className="flex items-center gap-1 text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-1 rounded-full hover:bg-blue-100 transition-colors"
                 >
                   <Plus size={10} /> LIST
                 </button>
              </div>
              <div className="space-y-2">
                {taskLists.map(list => (
                  <TaskListBlock 
                    key={list.id} 
                    list={list} 
                    onUpdate={(updated) => setTaskLists(taskLists.map(l => l.id === list.id ? updated : l))}
                    onDelete={() => setTaskLists(taskLists.filter(l => l.id !== list.id))}
                  />
                ))}
              </div>
            </div>

            {/* 5. Final Assets */}
            <div className="pt-2 border-t border-gray-100">
              <label className="text-[10px] font-bold text-emerald-600 uppercase tracking-widest mb-2 block">Final Assets</label>
              <div className="grid grid-cols-4 gap-2">
                {finalAssets.map((item, i) => (
                  <MediaCube 
                    key={item.id} 
                    item={item} 
                    index={i} 
                    onRemove={() => setFinalAssets(finalAssets.filter(r => r.id !== item.id))}
                    onUpdate={(updated) => setFinalAssets(finalAssets.map(r => r.id === item.id ? updated : r))}
                  />
                ))}
                {finalAssets.length < 4 && (
                   <button 
                    onClick={(e) => { e.stopPropagation(); setFinalAssets([...finalAssets, { id: Date.now().toString(), type: 'empty' }]); }}
                    className="aspect-square border border-dashed border-emerald-200 bg-emerald-50/30 rounded-md flex items-center justify-center text-emerald-400 hover:bg-emerald-50"
                   >
                     <Plus size={16} />
                   </button>
                )}
              </div>
            </div>
          </div>
        )}

        {/* VIEW MODE: COMMENTS */}
        {viewMode === 'comments' && (
          <div className="flex flex-col h-[400px] animate-in slide-in-from-right-4 duration-300">
             <div className="flex-1 overflow-y-auto space-y-3 p-1">
                {comments.length === 0 && (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400">
                    <MessageSquare size={32} className="mb-2 opacity-20"/>
                    <p className="text-xs">No comments yet</p>
                  </div>
                )}
                {comments.map(c => (
                  <div key={c.id} className="flex gap-2 text-sm">
                    <div className="w-6 h-6 rounded-full bg-gradient-to-tr from-purple-400 to-blue-400 text-white text-[10px] flex items-center justify-center font-bold flex-shrink-0">
                      {c.avatar}
                    </div>
                    <div className="bg-gray-100 p-2 rounded-lg rounded-tl-none">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="font-semibold text-gray-800 text-xs">{c.user}</span>
                        <span className="text-[10px] text-gray-400">{c.timestamp}</span>
                      </div>
                      <p className="text-gray-700 leading-snug">{c.text}</p>
                    </div>
                  </div>
                ))}
             </div>
             <div className="pt-3 mt-auto border-t border-gray-100 flex gap-2">
                <input 
                  className="flex-1 bg-gray-50 border border-gray-200 rounded-full px-3 py-1.5 text-sm focus:ring-2 focus:ring-purple-100 outline-none transition-all"
                  placeholder="Reply..."
                  value={newComment}
                  onChange={(e) => setNewComment(e.target.value)}
                  onKeyDown={(e) => { if(e.key === 'Enter') handlePostComment(); }}
                  onClick={(e) => e.stopPropagation()}
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); handlePostComment(); }}
                  className="w-8 h-8 rounded-full bg-purple-600 text-white flex items-center justify-center hover:bg-purple-700 shadow-sm"
                >
                  <Send size={14} />
                </button>
             </div>
          </div>
        )}

        {/* Footer Actions (Always Visible) */}
        <div className="mt-4 pt-3 border-t border-gray-100 flex items-center justify-between">
          <div className="flex items-center -space-x-2">
             <div className="w-6 h-6 rounded-full bg-blue-500 border-2 border-white flex items-center justify-center text-[10px] text-white font-bold cursor-help" title="John Doe">JD</div>
             <div className="w-6 h-6 rounded-full bg-emerald-500 border-2 border-white flex items-center justify-center text-[10px] text-white font-bold cursor-help" title="Sarah Smith">SS</div>
             <button className="w-6 h-6 rounded-full bg-gray-100 border-2 border-white flex items-center justify-center text-gray-400 hover:bg-gray-200 transition-colors">
               <UserPlus size={12} />
             </button>
          </div>

          <div className="flex gap-1 bg-gray-100 p-1 rounded-lg">
             <button 
              onClick={(e) => { e.stopPropagation(); setViewMode('edit'); }}
              className={`p-1.5 rounded-md transition-all ${viewMode === 'edit' ? 'bg-white text-gray-800 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <FileImage size={14} />
             </button>
             <button 
              onClick={(e) => { e.stopPropagation(); setViewMode('comments'); }}
              className={`p-1.5 rounded-md transition-all flex items-center gap-1 ${viewMode === 'comments' ? 'bg-white text-purple-600 shadow-sm' : 'text-gray-400 hover:text-gray-600'}`}
             >
               <MessageSquare size={14} />
               {comments.length > 0 && <span className="text-[9px] font-bold">{comments.length}</span>}
             </button>
          </div>
        </div>
      </div>
    </BaseCard>
  );
};

