import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'icon';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {
  // iOS Button Philosophy: Physical interactions, no sharp edges, system blue.
  const baseStyles = "inline-flex items-center justify-center font-medium transition-all duration-200 active:scale-[0.98] disabled:opacity-50 disabled:active:scale-100 select-none";

  const variants = {
    // Standard iOS Blue pill
    primary: "bg-[#007AFF] text-white rounded-full hover:bg-[#0071E3] shadow-sm",
    // Secondary gray button
    secondary: "bg-[#E5E5EA] text-[#007AFF] rounded-full hover:bg-[#D1D1D6]",
    // Text only
    ghost: "text-[#007AFF] hover:bg-black/5 rounded-lg",
    // Icon button
    icon: "text-[#007AFF] hover:bg-black/5 rounded-full p-2"
  };

  const sizes = {
    sm: "px-3 py-1 text-[13px] leading-4",
    md: "px-5 py-2 text-[15px] leading-5",
    lg: "px-6 py-3 text-[17px] leading-6"
  };

  const finalClass = `${baseStyles} ${variants[variant]} ${variant === 'icon' ? '' : sizes[size]} ${className}`;

  return (
    <button className={finalClass} {...props}>
      {children}
    </button>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CardData, CardType } from '../../types';
import { X } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title: string;
  accentColor?: string; // Kept for API compatibility, but usage will be subtle
  icon?: React.ReactNode;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete,
  zoomScale,
  children,
  title,
  icon
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });

  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(card.id);
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX, y: e.clientY };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale]);

  return (
    <div
      className={`absolute flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] ${
        isSelected ? 'shadow-[0_20px_40px_-12px_rgba(0,0,0,0.12)] z-50 scale-[1.005]' : 'shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)]'
      }`}
      style={{
        left: card.x,
        top: card.y,
        width: card.width,
        minHeight: card.height,
        borderRadius: '24px', // Continuous curve feel
      }}
      onClick={(e) => {
        e.stopPropagation();
        onSelect(card.id);
      }}
    >
      {/* Header - Native iOS feel: blended, no hard lines */}
      <div 
        className="flex items-center justify-between px-5 pt-5 pb-2 cursor-grab active:cursor-grabbing rounded-t-[24px]"
        onMouseDown={handleMouseDown}
      >
        <div className="flex items-center gap-2.5 text-gray-900 select-none">
          {/* Icons are subtle, secondary indicators */}
          <span className="text-gray-400">{icon}</span>
          {/* Title is bold but small, system font */}
          <span className="text-[13px] font-semibold tracking-tight text-gray-500">{title}</span>
        </div>

        {/* Close button - Physical feel */}
        <button 
          onClick={() => onDelete(card.id)} 
          className="w-6 h-6 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:bg-gray-200 hover:text-gray-600 transition-colors"
        >
          <X size={14} />
        </button>
      </div>

      {/* Content Area */}
      <div className="flex-1 px-5 pb-5 overflow-visible">
        {children}
      </div>
    </div>
  );
};

