  Layout, 
  Plus, 
  Settings, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'Summer Campaign',
    cards: [
      { id: 'card-post-1', type: CardType.POST, x: 400, y: 150, width: 360, height: 400, zIndex: 1, content: { title: 'Launch Teaser', date: '2024-06-01' } },
      { id: 'card-ai-1', type: CardType.STRATEGY_AI, x: 820, y: 150, width: 340, height: 300, zIndex: 2, content: {} }
    ]
  },
  {
    id: 'ws-2',
    name: 'Evergreen Content',
    cards: []
  }
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : 360,
      height: 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: 'New Space',
      cards: []
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  return (
    <div className="w-full h-screen flex overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Left Sidebar - Native iOS feel */}
      <div className="w-[280px] flex flex-col z-20 ios-glass border-r border-black/5">
        <div className="h-14 flex items-center px-5 mt-2">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 rounded-[8px] bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white shadow-sm">
               <Layout size={18} strokeWidth={2.5}/>
             </div>
             <span className="font-bold text-[17px] tracking-tight">Orbit</span>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto py-6 px-3">
          <div className="px-3 mb-2 text-[13px] font-semibold text-gray-400">Workspaces</div>
          <div className="space-y-0.5">
            {workspaces.map(ws => (
              <button
                key={ws.id}
                onClick={() => setActiveWorkspaceId(ws.id)}
                className={`w-full text-left px-3 py-2 rounded-[10px] text-[15px] transition-all duration-200 ${
                  activeWorkspaceId === ws.id 
                    ? 'bg-black/5 text-black font-medium' 
                    : 'text-gray-600 hover:bg-black/5'
                }`}
              >
                {ws.name}
              </button>
            ))}
          </div>
          <button 
            onClick={addWorkspace}
