        </div>

        <div className="p-4 border-t border-black/5">
          <div className="flex items-center gap-3 p-2 rounded-xl hover:bg-black/5 transition-colors cursor-pointer">
             <div className="w-9 h-9 rounded-full bg-gray-200 flex items-center justify-center text-gray-500 font-semibold text-xs">JD</div>
             <div className="flex-1">
               <div className="text-[15px] font-medium text-gray-900">John Doe</div>
               <div className="text-[13px] text-gray-500">Pro Plan</div>
             </div>
             <Settings size={20} className="text-gray-400"/>
          </div>
        </div>
      </div>

      {/* Main Canvas Area */}
      <div className="flex-1 relative">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />

        {/* Floating Toolbar - Dynamic Island / Floating Palette feel */}
        <div className="absolute top-6 left-1/2 -translate-x-1/2 ios-glass rounded-full px-2 py-1.5 flex items-center gap-1 z-30 shadow-[0_8px_32px_rgba(0,0,0,0.12)] scale-100 animate-in fade-in slide-in-from-top-4 duration-500 ease-out">
